import matplotlib.pyplot as plt
import numpy as np
from sklearn.metrics import auc

def plot_pr_curve(p2, r2):
    # Ensure the data is sorted by recall
    sorted_indices = np.argsort(r2)
    r2 = np.array(r2)[sorted_indices]
    p2 = np.array(p2)[sorted_indices]
    
    # Compute area under the curve
    pr_auc = auc(r2, p2)
    
    # Plot P-R curve
    plt.figure(figsize=(8, 6))
    plt.plot(r2, p2, marker='o', linestyle='-', label=f'PR Curve (AUC = {pr_auc:.4f})', color='b')
    plt.xlabel('Recall')
    plt.ylabel('Precision')
    plt.title('Precision-Recall Curve')
    plt.legend()
    plt.grid()
    plt.show()
    
    print(f'Area Under Curve (AUC-PR): {pr_auc:.4f}')

